              <div style={{ fontSize: 11, color: 'var(--text3)', marginTop: 4 }}>Поток 12 — {Math.floor(Math.random() * 150 + 50)} учеников</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
